class Solution {
public:
    int countLargestGroup(int n) {
        int max = 0, count = 0;
        unordered_map<int, int> groups;
        for (int i = 1; i <= n; i++) {
            int sum = 0;
            int num = i;
            while (num > 0) {
                sum += num % 10;
                num /= 10;
            }
            groups[sum]++;
            max = std::max(max, groups[sum]);
        }
        for (auto& pair : groups) {
            if (pair.second == max) count++;
        }
        return count;
    }
};
```

